    "context": "Conversa importada do ChatGPT para a pasta Biohacker Engine.",
    "content": "from artifact_tool import Workbook, SpreadsheetFile\nfrom datetime import datetime\n\nwb = Workbook.create()\n# Create sheets\nsheets = {}\nfor name in [\"01_Aluno\", \"02_Calculo\", \"03_Treino_Volume\", \"04_Dieta_Macros\", \"05_Calibracao\", \"06_Motor\"]:\n    sheets[name] = wb.worksheets.add(name)\n\n# Define styles\ndark = \"#111827\"\ngreen = \"#0F766E\"\nblue = \"#1D4ED8\"\namber = \"#B45309\"\nlight_green = \"#DCFCE7\"\nlight_blue = \"#DBEAFE\"\nlight_amber = \"#FEF3C7\"\nlight_gray = \"#F3F4F6\"\nwhite = \"#FFFFFF\"\nred = \"#B91C1C\"\n\ndef title(sheet, cell_range, text, fill=dark):\n    sheet.get_range(cell_range).merge()\n    cell = cell_range.split(\":\")[0]\n    sheet.get_range(cell).values = [[text]]\n    r = sheet.get_range(cell_range)\n    r.format = {\"fill\": fill, \"font\": {\"bold\": True, \"color\": white, \"size\": 15},\n                \"horizontal_alignment\": \"center\", \"vertical_alignment\": \"center\"}\n    r.format.row_height = 28\n\ndef header(rng, fill=green):\n    rng.format = {\"fill\": fill, \"font\": {\"bold\": True, \"color\": white},\n                  \"horizontal_alignment\": \"center\", \"vertical_alignment\": \"center\",\n                  \"borders\": {\"color\": \"#D1D5DB\", \"style\": \"continuous\"}}\ndef body(rng):\n    rng.format = {\"fill\": white, \"font\": {\"color\": \"#111827\", \"size\": 10},\n                  \"vertical_alignment\": \"top\", \"wrap_text\": True,\n                  \"borders\": {\"color\": \"#E5E7EB\", \"style\": \"continuous\"}}\n\n# 01_Aluno\nsh = sheets[\"01_Aluno\"]\ntitle(sh, \"A1:H1\", \"PLANILHA CORPO-SISTEMA — WELLINGTON STOLL\", dark)\nsh.get_range(\"A3:B14\").values = [\n    [\"ALUNO\", \"Wellington Stoll\"],\n    [\"Idade\", 37],\n    [\"Sexo\", \"Masculino\"],\n    [\"Altura (cm)\", 171],\n    [\"Peso atual (kg)\", 91],\n    [\"Objetivo\", \"Músculos / definição\"],\n    [\"Trabalho / rotina diária\", \"Não informado\"],\n    [\"Musculação\", \"3x por semana\"],\n    [\"Cardio ou esporte\", \"-\"],\n    [\"Frequência cardio/esporte\", \"-\"],\n    [\"Status do peso\", \"Caindo\"],\n    [\"Sono\", \"8h\"],\n]\nheader(sh.get_range(\"A3:B3\"), blue)\nbody(sh.get_range(\"A4:B14\"))\nsh.get_range(\"A16:H16\").merge()\nsh.get_range(\"A16\").values = [[\"LEITURA DO SISTEMA\"]]\nheader(sh.get_range(\"A16:H16\"), green)\nsh.get_range(\"A17:H22\").values = [\n    [\"Fato\", \"Ele voltou a treinar e já perdeu peso.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n    [\"Contexto\", \"Não é iniciante puro. Pré-intermediário: já faz supino, leg, puxada e remada, mas precisa de volume com lógica.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n    [\"Mecanismo\", \"Se o peso está caindo sem dieta estruturada, provavelmente está em déficit calórico espontâneo. Para definir com músculo, precisa manter proteína alta e controlar queda de peso.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n    [\"Conclusão\", \"Estratégia inicial: recomposição/definição controlada. Não fazer força aleatória; organizar volume semanal, progressão e dieta base.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n    [\"Prioridade 1\", \"Treino 3x bem estruturado com volume semanal por grupo muscular.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n    [\"Prioridade 2\", \"Dieta simples com proteína suficiente e calorias próximas da manutenção.\", \"\", \"\", \"\", \"\", \"\", \"\"],\n]\nbody(sh.get_range(\"A17:H22\"))\nsh.get_range(\"A17:A22\").format = {\"fill\": light_blue, \"font\": {\"bold\": True}}\nsh.get_range(\"A:B\").format.column_width = 24\nsh.get_range(\"B:B\").format.column_width = 38\nsh.get_range(\"C:H\").format.column_width = 15\n\n# 02_Calculo\nsh = sheets[\"02_Calculo\"]\ntitle(sh, \"A1:H1\", \"CÁLCULO — TMB, TDEE E ALVO\", dark)\nsh.get_range(\"A3:D12\").values = [\n    [\"INPUT\", \"VALOR\", \"UNIDADE\", \"OBS\"],\n    [\"Peso\", 91, \"kg\", \"Peso atual\"],\n    [\"Altura\", 171, \"cm\", \"Informado\"],\n    [\"Idade\", 37, \"anos\", \"Informado\"],\n    [\"Sexo\", \"Masculino\", \"\", \"Mifflin-St Jeor\"],\n    [\"Fator de atividade\", 1.45, \"\", \"Pré-intermediário, musculação 3x, sem cardio\"],\n    [\"Objetivo\", \"Músculos / definição\", \"\", \"Recomposição controlada\"],\n    [\"Status do peso\", \"Caindo\", \"\", \"Evitar déficit agressivo\"],\n    [\"Sono\", 8, \"h\", \"Bom para recuperação\"],\n    [\"Cardio\", 0, \"x/sem\", \"Sem cardio atualmente\"],\n]\nheader(sh.get_range(\"A3:D3\"), blue)\nbody(sh.get_range(\"A4:D12\"))\nsh.get_range(\"F3:H11\").values = [\n    [\"MOTOR\", \"FÓRMULA\", \"RESULTADO\"],\n    [\"TMB\", \"=10*Peso + 6,25*Altura - 5*Idade + 5\", \"\"],\n    [\"TMB calculada\", \"\", \"\"],\n    [\"TDEE\", \"=TMB * FA\", \"\"],\n    [\"TDEE calculado\", \"\", \"\"],\n    [\"Alvo mínimo\", \"TDEE - 150\", \"\"],\n    [\"Alvo central\", \"TDEE\", \"\"],\n    [\"Alvo alto\", \"TDEE + 150\", \"\"],\n    [\"Status\", \"Usar faixa conforme peso\", \"\"],\n]\nheader(sh.get_range(\"F3:H3\"), green)\nbody(sh.get_range(\"F4:H11\"))\n# Set formulas referencing cells\nsh.get_range(\"H5\").f\n\n[conteúdo cortado para caber na página]",
